@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="infinite-scroll-spinner" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? moduleRef;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            moduleRef = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-fd595ffefc6d48788e37de8ab2046aa9/Components/InfiniteScrollList.razor.js");
            dotNetRef = DotNetObjectReference.Create(this);
        }

        if (HasMore && moduleRef is not null)
        {
            await moduleRef.InvokeVoidAsync("observe", sentinelRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore)
            return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (moduleRef is not null)
        {
            try
            {
                await moduleRef.InvokeVoidAsync("disconnect");
                await moduleRef.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        dotNetRef?.Dispose();
    }
}

let observer = null;

export function observe(sentinel, dotNetRef) {
    disconnect();

    observer = new IntersectionObserver(entries => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetRef.invokeMethodAsync('OnSentinelVisible');
            }
        }
    }, { rootMargin: '128px' });

    observer.observe(sentinel);
}

export function disconnect() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
    min-height: 1px;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 0.25rem solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.75s linear infinite;
}

@keyframes infinite-scroll-spin {
    to { transform: rotate(360deg); }
}

